from __future__ import annotations
import copy
from arcgis.auth.tools import LazyLoader
from arcgis.auth import EsriSession
from typing import Any, Literal
from arcgis.ai._utils import (
    AIUtilsException,
    _get_url,
    _get_gis,
    AIUtilsResponse,
    _handle_ai_response,
)

_arcgis_gis = LazyLoader("arcgis.gis")

__all__ = ["translate", "analyze_text"]


# -------------------------------------------------------------------------
def translate(
    text: str | list[str],
    to_language: list[str],
    from_language: str | None = "en",
    *,
    gis: _arcgis_gis.GIS | None = None,
) -> AIUtilsResponse | AIUtilsException:
    """
    Translates language strings passed to the desired array of output cultures.

    ===============     ====================================================================
    **Parameter**        **Description**
    ---------------     --------------------------------------------------------------------
    text                Required string or list of strings. The text to translate.
    ---------------     --------------------------------------------------------------------
    to_language         Required list of strings. The list of languages to convert to.
                        To see a list of supported languages, use the
                        :attr:`~arcgis.gis.GIS.languages` property of a :class:`~arcgis.gis.GIS`
                        object.

                        .. code-block:: python

                            # Example argument formatting:
                            result = translate(
                                       ...
                                       to_language = ["fr", "de"], # French, German
                                      ...
                            )
    ---------------     --------------------------------------------------------------------
    from_language       Optional str. The source language.  The default is US English.
                        To see a list of supported languages, use the
                        :attr:`~arcgis.gis.GIS.languages` property of a :class:`~arcgis.gis.GIS`
                        object.
    ---------------     --------------------------------------------------------------------
    gis                 Optional :class:`~arcgis.gis.GIS`. The connection to the organization
                        that has AI assistants enabled.
    ===============     ====================================================================

    :return:
        An :class:`~arcgis.ai.AIUtilsResponse` object containing the translations
        accessible through the :attr:`~arcgis.ai.AIUtilsResponse.results` property.

    .. code-block:: python

        # Example usage
        from arcgis.gis import GIS
        from arcgis.ai import translate

        # Connect to GIS (ensure you have the correct organization set up with AI assistants enabled)
        gis = GIS(profile="your_profile")

        # Translate a single string to French and German
        response = translate(
            text="What departments border Moselle?",
            to_language=["fr", "de"],
            from_language="en",
        )

        print(response.results)
        >>>[
            TranslateResult(
                translations=[
                    {'text': 'Quels départements bordent la Moselle ?', 'to': 'fr'},
                    {'text': 'Welche Départamentos grenzen an Moselle?', 'to': 'de'}
                ],
                key='key:1')
           ]
    """
    # Get the GIS and service URL
    gis = _get_gis(gis)
    service_url: str = _get_url(gis=gis, utility_service="text_translate")
    if service_url is None:
        raise ValueError(
            "The text translation service is not available in your organization."
        )
    session: EsriSession = gis.session

    # Prepare text data
    if isinstance(text, str):
        text = [{"key": "key:1", "text": text}]
    elif isinstance(text, (list, tuple)):
        text = [{"key": f"key:{idx}", "text": t} for idx, t in enumerate(text)]
    if isinstance(to_language, str):
        to_language = [to_language]

    if from_language is None:
        from_language = "en"

    if text is None or len(text) == 0:
        raise ValueError(
            "The text parameter must contain at least one string to translate."
        )

    # Prepare request parameters
    params: dict[str, Any] = {
        "outputCultures": to_language,
        "inputCulture": from_language,
        "input": text,
    }

    # Prepare headers and make the POST request
    headers = copy.copy(session.headers)
    headers["x-esri-request-source"] = "ArcGIS-API-For-Python"
    resp = session.post(
        url=service_url,
        json=params,
        headers=headers,
        allow_redirects=True,
    )

    return _handle_ai_response(resp)


# -------------------------------------------------------------------------
def analyze_text(
    text: str,
    prompt: str | list[str] | list[dict[str, str]],
    to_language: str | None = None,
    from_language: str | None = None,
    *,
    gis: _arcgis_gis.GIS | None = None,
) -> AIUtilsResponse | AIUtilsException:
    """
    Analyzes the provided text against the given prompt(s) using AI capabilities. Allows users to submit
    text for analysis, which can include tasks such as sentiment analysis, entity recognition, and other
    natural language processing operations.

    ===============     ====================================================================
    **Parameter**        **Description**
    ---------------     --------------------------------------------------------------------
    text                Required string. The text to analyze.
    ---------------     --------------------------------------------------------------------
    prompt              Required string, list of strings, or list of dictionaries. Defines
                        the types analysis to perform.

                        * If a string or list of strings, these are the prompts or instructions.
                        * If a dictionary, keys are labels for each analysis type and values
                          are the corresponding prompts/instructions.

                        .. code-block:: python

                            # Usage example 1 : argument as a string:
                            result = analyze_text(
                                        ...
                                        prompt = "Summarize the following text.",
                                        ...
                            )

                            # Usage example 2: argument as list of strings:
                            result = analyze_text(
                                        ...
                                        prompt = [
                                            "Summarize the following text.",
                                            "Extract key entities from the following text."
                                        ],
                                        ...
                            )

                            # Usage example 3: argument as list of dictionaries:
                            result = analyze_text(
                                        ...
                                        prompt = [
                                            {
                                                "key": "summarize_prompt",
                                                "context": "Summarize the following text."
                                            },
                                            {
                                                "key": "entities_prompt",
                                                "context": "Extract key entities from the following text."
                                            }
                                        ],
                                        ...
                             )
    ---------------     --------------------------------------------------------------------
    to_language         Optional string. The output language for analysis. Default is
                        "en". To see a list of supported languages, use the
                        :attr:`~arcgis.gis.GIS.languages` property of a :class:`~arcgis.gis.GIS`
                        object.
    ---------------     --------------------------------------------------------------------
    from_language       Optional string. The source language of the input text. Default is
                        "en". To see a list of supported languages, use the
                        :attr:`~arcgis.gis.GIS.languages` property of a :class:`~arcgis.gis.GIS`
                        object.
    ---------------     --------------------------------------------------------------------
    gis                 Optional :class:`~arcgis.gis.GIS`. The connection to the organization
                        that has AI assistants enabled.
    ===============     ====================================================================

    :return:
        :class:`~arcgis.ai.AIUtilsResponse` or :class:`~arcgis.ai.AIUtilsException`
        containing the the analysis results.

    .. code-block:: python

        # Usage Example 1: Usage of the function:
        from arcgis.gis import GIS
        from arcgis.ai import analyze_text

        # Connect to GIS (ensure you have the correct organization set up with AI assistants enabled)
        gis = GIS(profile="your_organization_profile")

        # Analyze text with a single prompt
        response = analyze_text(
            text="ArcGIS is a powerful geographic information system.",
            prompt="What are the key entities in this text?",
            to_language="en",
            from_language="en",
        )

        print(response.success)
        >>> True

        print(response.results)
        >>> [AnalyzeResult(success=True, value=['ArcGIS', 'geographic information system'], key='key:1')]


        # Usage Example 2: Using multiple prompts:

        response = analyze_text(
            text="ArcGIS is a powerful geographic information system.",
            prompt=[
                "What are the key entities in this text?",
                "Summarize the main idea of this text."
            ],
            to_language="en",
            from_language="en",
        )
        print(response)

        # Usage Example 3: Using dictionary prompts:
        response = analyze_text(
            text="ArcGIS is a powerful geographic information system.",
            prompt=[
                {
                    "key": "entities",
                    "context": "What are the key entities in this text?"
                },
                {
                    "key": "summary",
                    "context": "Summarize the main idea of this text."
                }
            ],
            to_language="en",
            from_language="en",
        )

        print(type(response))
        >>> <class 'arcgis.ai._utils.AIUtilsResponse'>

        print(response.results)
        >>> [
             AnalyzeResult(success=True,
                           value=['ArcGIS', 'geographic information system'],
                           key='entities'),
             AnalyzeResult(success=True,
                           value='ArcGIS is described as a powerful geographic information system.',
                           key='summary')
            ]


    """
    # Get the GIS and service URL
    gis = _get_gis(gis)
    service_url: str = _get_url(gis=gis, utility_service="text_analyze")
    if service_url is None:
        raise ValueError(
            "The text analysis service is not available in your organization."
        )
    session: EsriSession = gis.session

    # Prepare prompt data
    if isinstance(prompt, str):
        context = [{"key": "key:1", "context": prompt}]
    elif isinstance(prompt, (list, tuple)):
        # Flatten if prompt is a list of dicts (already formatted), else convert each string to dict
        if prompt and all(
            isinstance(t, dict) and "key" in t and "context" in t for t in prompt
        ):
            context = prompt  # Already in correct format
        else:
            context = [
                {"key": f"unique_string_{idx}", "context": t}
                for idx, t in enumerate(prompt)
            ]

    if context is None or len(context) == 0:
        raise ValueError(
            "The prompt parameter must contain at least one prompt and be of type `str`, `list[str]`, or `list[dict[str, str]]`."
        )

    # Prepare request parameters
    params: dict[str, Any] = {
        "input": text,
        "data": context,
    }
    if to_language:
        params["outputCulture"] = to_language
    if from_language:
        params["inputCulture"] = from_language

    # Prepare headers and make the POST request
    headers = copy.copy(session.headers)
    headers["x-esri-request-source"] = "ArcGIS-API-For-Python"
    resp = session.post(
        url=service_url,
        json=params,
        headers=headers,
        allow_redirects=True,
    )

    return _handle_ai_response(resp)
